      columns = drive_result,
      rows = drive_result %in% c("TD", "FG", "FUMBLE", "INT", "INT RETURN")
    )
  ) |>
  gtUtils::gt_538_caption(
    top_caption = "Points per drive (ppd) based on drive results. Available yards using the start as the
  distance to the goal. Summary stats shows average start, yds/play, and available yards percentage.",
    bottom_caption = "Data via {cfbfastR}, built with {gtUtils} | Table by Chris at Bless your chart"
  ) |>
  gt::tab_options(table.width = gt::px(400))  -> gt_dc_tab_2

gtUtils::gt_stack_tables(list(gt_dc_tab_1, gt_dc_tab_2)) -> tabs

gtUtils::gt_save_crop(tabs,
                      file = "drive_table.png",
                      whitespace = 40,
                      bg = "white")

tabs
